import { Component, OnInit } from '@angular/core';
import { FormBuilder, FormGroup, ReactiveFormsModule, Validators } from '@angular/forms';
import { StaffService } from '../../../../core/services/staff.service';
import { ActivatedRoute, Router } from '@angular/router';
import { CommonModule } from '@angular/common';

@Component({
  selector: 'app-staff-form',
  imports: [CommonModule, ReactiveFormsModule],
  templateUrl: './staff-form.component.html',
  styleUrl: './staff-form.component.css'
})
export class StaffFormComponent implements OnInit{
staffForm!: FormGroup;
  isEditMode = false;
  staffId!: number;
  loading = false;

  constructor(
    private fb: FormBuilder,
    private staffService: StaffService,
    private route: ActivatedRoute,
    private router: Router
  ) {}

  ngOnInit(): void {
    this.initForm();

    // ✅ Check Edit Mode
    this.staffId = Number(this.route.snapshot.paramMap.get('id'));
    if (this.staffId) {
      this.isEditMode = true;
      this.getStaffById();
    }
  }

  /**
   * ✅ Initialize Form
   */
  initForm() {
    this.staffForm = this.fb.group({
      name: ['', Validators.required],
      mobile: ['', [Validators.required, Validators.pattern(/^[0-9]{10}$/)]],
      role: ['', Validators.required],
      category: ['', Validators.required],
      salary: ['', [Validators.required, Validators.min(0)]],
      address: [''],
      joiningDate: [''],
      status: ['ACTIVE']
    });
  }

  /**
   * ✅ Load Staff Data (Edit)
   */
  getStaffById() {
    this.staffService.getStaffById(this.staffId).subscribe({
      next: (res:any) => {
        this.staffForm.patchValue(res.data);
      },
      error: (err:any) => {
        console.error(err);
      }
    });
  }

  /**
   * ✅ Submit Form
   */
  onSubmit() {
    if (this.staffForm.invalid) {
      this.staffForm.markAllAsTouched();
      return;
    }

    this.loading = true;

    const formData = this.staffForm.value;

    if (this.isEditMode) {
      this.staffService.updateStaff(this.staffId, formData).subscribe({
        next: () => {
          this.loading = false;
          this.router.navigate(['/staff']);
        },
        error: () => {
          this.loading = false;
        }
      });
    } else {
      this.staffService.createStaff(formData).subscribe({
        next: () => {
          this.loading = false;
          this.router.navigate(['/staff']);
        },
        error: () => {
          this.loading = false;
        }
      });
    }
  }
}
